const results = [];
const nowText = new Date().toLocaleString('sv-SE', { timeZone: 'Asia/Shanghai' }).replace(' ', 'T');
const ts = `${nowText.substring(0, 16)}:00+08:00`;

function sqlText(value) {
  if (value === null || value === undefined) return 'NULL';
  return `'${String(value).replace(/'/g, "''")}'`;
}

function sqlNumber(value) {
  const number = Number(value);
  return Number.isFinite(number) ? String(number) : 'NULL';
}

function addRecord({ source, metric, value = null, textValue = null, unit = '', confidence = 'measured', raw = {}, recordTs = ts }) {
  const sql = `
    INSERT INTO crowd_data (ts, source, metric, value, text_value, unit, confidence, raw_json, created_at)
    VALUES (${sqlText(recordTs)}, ${sqlText(source)}, ${sqlText(metric)}, ${sqlNumber(value)}, ${sqlText(textValue)}, ${sqlText(unit)}, ${sqlText(confidence)}, ${sqlText(JSON.stringify(raw || {}))}, NOW())
    ON CONFLICT (ts, source, metric) DO UPDATE SET
      value = EXCLUDED.value,
      text_value = EXCLUDED.text_value,
      unit = EXCLUDED.unit,
      confidence = EXCLUDED.confidence,
      raw_json = EXCLUDED.raw_json,
      created_at = NOW()
    WHERE crowd_data.value IS DISTINCT FROM EXCLUDED.value
      OR crowd_data.text_value IS DISTINCT FROM EXCLUDED.text_value
      OR crowd_data.unit IS DISTINCT FROM EXCLUDED.unit
      OR crowd_data.confidence IS DISTINCT FROM EXCLUDED.confidence
      OR crowd_data.raw_json IS DISTINCT FROM EXCLUDED.raw_json
  `;
  results.push({ sql, label: `${source}.${metric}` });
}

// 1. Gov tour
try {
  const govData = $('获取景区数据').first().json;
  const spot = (govData.rows || []).find((r) => String(r.NAME || '').includes('田子坊'));
  if (spot && spot.NUM !== undefined && spot.NUM !== null) {
    let skip = false;
    if (spot.TIME) {
      const apiTime = new Date(`${spot.TIME.replace(' ', 'T')}+08:00`);
      if ((Date.now() - apiTime.getTime()) / 60000 > 30) skip = true;
    }
    if (!skip) {
      addRecord({
        source: 'gov_tour',
        metric: 'in_park_count',
        value: spot.NUM,
        unit: '人',
        confidence: 'measured',
        raw: {
          source: 'sh_a_scenic_realtime',
          code: spot.CODE,
          name: spot.NAME,
          time: spot.TIME,
          grade: spot.GRADE,
          comfort: spot.SSD,
          max_num: spot.MAX_NUM,
          type: spot.TYPE,
          district: spot.DNAME,
        },
      });
    }
  }
} catch (e) {
  addRecord({ source: 'collector:gov_tour', metric: 'collector_status', value: 0, textValue: 'error', confidence: 'unavailable', raw: { error: e.message } });
}

// 2. Weather - wttr.in format=j1
try {
  const wData = $('获取天气').first().json;
  const c = wData.current_condition?.[0] || {};
  const today = wData.weather?.[0] || {};
  const desc = c.lang_zh?.[0]?.value || c.weatherDesc?.[0]?.value || '';

  addRecord({ source: 'weather', metric: 'temperature', value: c.temp_C, unit: '℃', raw: { feels_like: Number(c.FeelsLikeC) } });
  addRecord({ source: 'weather', metric: 'humidity', value: c.humidity, unit: '%' });
  addRecord({ source: 'weather', metric: 'wind_speed', value: c.windspeedKmph, unit: 'km/h' });
  if (today.maxtempC != null) addRecord({ source: 'weather', metric: 'temperature_max', value: today.maxtempC, unit: '℃' });
  if (today.mintempC != null) addRecord({ source: 'weather', metric: 'temperature_min', value: today.mintempC, unit: '℃' });
  if (desc) addRecord({ source: 'weather', metric: 'weather_desc', textValue: desc, raw: { raw: c } });
} catch (e) {
  addRecord({ source: 'collector:weather', metric: 'collector_status', value: 0, textValue: 'error', confidence: 'unavailable', raw: { error: e.message } });
}

// 3. Holiday - use day-start timestamp so repeated N8N runs update one daily row per metric.
try {
  const date = ts.substring(0, 10);
  const recordTs = `${date}T00:00:00+08:00`;
  const [year, month, day] = date.split('-').map(Number);
  if (year !== 2026) throw new Error(`Holiday year ${year} is not configured`);
  const weekday = new Date(`${date}T12:00:00+08:00`).getDay();
  const wd = weekday === 0 ? 6 : weekday - 1;
  const holidays = [[1,1,'元旦'],[1,2,'元旦假期'],[1,3,'元旦假期'],[2,15,'春节假期'],[2,16,'除夕'],[2,17,'春节'],[2,18,'春节假期'],[2,19,'春节假期'],[2,20,'春节假期'],[2,21,'春节假期'],[2,22,'春节假期'],[2,23,'春节假期'],[4,4,'清明节'],[4,5,'清明假期'],[4,6,'清明假期'],[5,1,'劳动节'],[5,2,'劳动节假期'],[5,3,'劳动节假期'],[5,4,'劳动节假期'],[5,5,'劳动节假期'],[6,19,'端午节'],[6,20,'端午假期'],[6,21,'端午假期'],[9,25,'中秋节'],[9,26,'中秋假期'],[9,27,'中秋假期'],[10,1,'国庆节'],[10,2,'国庆假期'],[10,3,'国庆假期'],[10,4,'国庆假期'],[10,5,'国庆假期'],[10,6,'国庆假期'],[10,7,'国庆假期']];
  const workdays = [[1,4,'元旦调休上班'],[2,14,'春节调休上班'],[2,28,'春节调休上班'],[5,9,'劳动节调休上班'],[9,20,'国庆调休上班'],[10,10,'国庆调休上班']];
  let isHoliday = 0;
  let holidayName = '';
  for (const [m, d, name] of holidays) {
    if (m === month && d === day) { isHoliday = 1; holidayName = name; break; }
  }
  let isWorkdayOverride = false;
  for (const [m, d, name] of workdays) {
    if (m === month && d === day) { isWorkdayOverride = true; holidayName = name; break; }
  }
  const isWorkday = (wd < 5 && !isHoliday) || isWorkdayOverride ? 1 : 0;

  addRecord({ source: 'holiday', metric: 'is_holiday', value: isHoliday, unit: 'bool', raw: { holiday_name: holidayName }, recordTs });
  addRecord({ source: 'holiday', metric: 'is_workday', value: isWorkday, unit: 'bool', raw: { weekday: wd, override: isWorkdayOverride }, recordTs });
  addRecord({ source: 'holiday', metric: 'weekday', value: wd, unit: 'day', raw: {}, recordTs });
} catch (e) {
  addRecord({ source: 'collector:holiday', metric: 'collector_status', value: 0, textValue: 'error', confidence: 'unavailable', raw: { error: e.message } });
}

return results.map((r) => ({ json: r }));
